{
  "data": [
    {
      "type": "osm",
      "pbfFileUrl": "docs/examples/data/back_bay.osm.pbf",
      "queryArea": {
        "geocodeArea": "Boston",
        "areas": [
          "Back Bay"
        ]
      },
      "outputTableName": "table_osm",
      "autoLoadLayers": {
        "layers": [
          "surface",
          "parks",
          "buildings"
        ],
        "dropOsmTable": true
      }
    }
  ],
  "compute": [
    {
      "dataRef": "table_osm_buildings",
      "attributes": {
        "ring": "geometry.coordinates.0",
        "h": "height"
      },
      "attributeMatrices": {
        "ring": {
          "rows": "auto",
          "cols": 2
        }
      },
      "outputColumnName": "height_mod",
      "wglsFunction": "var area: f32 = 0.0;\nlet nrows = ring_rows;\nif (nrows >= 3u) {\n  for (var i: u32 = 0u; i < nrows; i = i + 1u) {\n    let j = (i + 1u) % nrows;\n    let xi = ring[i * 2u]; let yi = ring[i * 2u + 1u];\n    let xj = ring[j * 2u]; let yj = ring[j * 2u + 1u];\n    area = area + (xi * yj - xj * yi);\n  }\n  area = abs(area) * 0.5;\n}\n// Back Bay buildings load in EPSG:3395, so `area` is in m^2. Tall = footprint > 200 m^2.\nlet base = select(h, 10.0, h <= 0.0);\nif (area > 200.0) { return base * 3.0; }\nreturn base;\n"
    }
  ],
  "map": {
    "layerRefs": [
      {
        "dataRef": "table_osm_surface"
      },
      {
        "dataRef": "table_osm_parks"
      },
      {
        "dataRef": "table_osm_buildings",
        "getFnv": "compute.height_mod",
        "getFnvType": "quantitative",
        "defaultFnv": 10
      }
    ]
  }
}
